#include <bits/stdc++.h>
using namespace std;
#define int unsigned long long
const int b=131,maxn=5e5+5;
int n,h1[maxn],h2[maxn],p[maxn];
string s;
void init_hash() {
}
int get1(int l,int r) {
	return h1[r]-h1[l-1]*p[r-l+1];
}
int get2(int l,int r) {
	return h2[l]-h2[r+1]*p[r-l+1];
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>s;
	n=s.length();
	s=s;
	init_hash();
	int l0=0;
	while(l0<n/2&&s[l0]==s[n-1-l0]) {
		l0++;
	}
	if(l0==n/2) {
		cout<<n/2;
		return 0;
	}
	int m=n-2*l0;
	string t=s.substr(l0,m);
	p[0]=1;
	for(int i=1; i<=m; i++) {
		h1[i]=h1[i-1]*b+t[i-1];
		p[i]=p[i-1]*b;
	}
	for(int i=m; i>=1; i--) {
		h2[i]=h2[i+1]*b+t[i-1];
	}
	int ans=0;
	for(int i=1; i<=m; i++) {
		while(2*(ans+1)<=i&&get1(1,ans+1)==get2(i-ans,i)) {
			ans++;
		}
	}
	for(int i=m; i>=1; i--) {
		while(2*(ans+1)<=m-i+1&&get1(i,ans+i)==get2(m-ans,m)) {
			ans++;
		}
	}
	cout<<ans+l0;
	return 0;
}
